INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'mq', 5, 1, NULL, 'Thomas Watson em Mq 5:1', 'Na leitura de Thomas Watson, vemos a piedade prática e a santificação do coração. Miqueias 5 evidencia arrependimento, justiça e restauração como eixo da vida do povo de Deus, com ênfase em amor fraternal. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Thomas Watson', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'mq', 6, 1, NULL, 'Andrew Murray em Mq 6:1', 'Segundo Andrew Murray, a coerência doutrinária aplicada à vida cristã ilumina o sentido deste texto. Miqueias 6 mostra que arrependimento, justiça e restauração sustenta a caminhada da fé, especialmente em arrependimento sincero. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Andrew Murray', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'mq', 7, 1, NULL, 'Orígenes em Mq 7:1', 'Orígenes destaca a leitura cristológica e eclesial da passagem. Em Miqueias 7, o foco recai sobre arrependimento, justiça e restauração e chama a igreja para vida de oração. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Orígenes', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), 'na', 1, 1, NULL, 'Joseph Benson em Na 1:1', 'Segundo Joseph Benson, a exposição textual com aplicação pastoral objetiva ilumina o sentido deste texto. Naum 1 mostra que arrependimento, justiça e restauração sustenta a caminhada da fé, especialmente em esperança escatológica. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Joseph Benson', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'na', 2, 1, NULL, 'Martin Bucer em Na 2:1', 'Martin Bucer destaca a centralidade das Escrituras e da graça soberana. Em Naum 2, o foco recai sobre arrependimento, justiça e restauração e chama a igreja para santidade prática. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Martin Bucer', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'na', 3, 1, NULL, 'Charles Finney em Na 3:1', 'Charles Finney interpreta este versículo a partir de o chamado ao arrependimento, fé viva e missão. Em Naum 3, Deus revela arrependimento, justiça e restauração de forma pastoral e transformadora, promovendo justiça com misericórdia. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Charles Finney', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), 'hc', 1, 1, NULL, 'E. M. Bounds em Hc 1:1', 'E. M. Bounds destaca a coerência doutrinária aplicada à vida cristã. Em Habacuque 1, o foco recai sobre arrependimento, justiça e restauração e chama a igreja para fidelidade na aliança. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'E. M. Bounds', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'hc', 2, 1, NULL, 'Atanásio em Hc 2:1', 'Na leitura de Atanásio, vemos a leitura cristológica e eclesial da passagem. Habacuque 2 evidencia arrependimento, justiça e restauração como eixo da vida do povo de Deus, com ênfase em arrependimento sincero. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Atanásio', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), 'hc', 3, 1, NULL, 'Thomas Watson em Hc 3:1', 'Segundo Thomas Watson, a piedade prática e a santificação do coração ilumina o sentido deste texto. Habacuque 3 mostra que arrependimento, justiça e restauração sustenta a caminhada da fé, especialmente em esperança escatológica. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Thomas Watson', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'sf', 1, 1, NULL, 'John Brown of Haddington em Sf 1:1', 'Na leitura de John Brown of Haddington, vemos a piedade prática e a santificação do coração. Sofonias 1 evidencia arrependimento, justiça e restauração como eixo da vida do povo de Deus, com ênfase em adoração reverente. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'John Brown of Haddington', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'sf', 2, 1, NULL, 'Albert Barnes em Sf 2:1', 'Segundo Albert Barnes, a exposição textual com aplicação pastoral objetiva ilumina o sentido deste texto. Sofonias 2 mostra que arrependimento, justiça e restauração sustenta a caminhada da fé, especialmente em amor fraternal. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Albert Barnes', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'sf', 3, 1, NULL, 'Martinho Lutero em Sf 3:1', 'Martinho Lutero destaca a centralidade das Escrituras e da graça soberana. Em Sofonias 3, o foco recai sobre arrependimento, justiça e restauração e chama a igreja para fidelidade na aliança. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Martinho Lutero', 'commentary', '#800080', NOW()),
